function ipToInt(ip) {
  if (!ip || ip.includes(':')) return 0;
  const p = ip.split('.');
  if (p.length !== 4) return 0;
  return ((+p[0]) * 16777216) + ((+p[1]) * 65536) + ((+p[2]) * 256) + (+p[3]);
}

function lookupCity(ipInt) {
  let lo = 0, hi = RU_TABLE.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >> 1;
    const [from, to, idx] = RU_TABLE[mid];
    if (ipInt < from) hi = mid - 1;
    else if (ipInt > to) lo = mid + 1;
    else return RU_CITIES[idx] || null;
  }
  return null;
}

// In-memory кэш (пока serverless instance жив)
const MEM_CACHE = {};

function cors(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, X-API-Key');
}

export default async function handler(req, res) {
  cors(res);
  if (req.method === 'OPTIONS') return res.status(204).end();

  const ip = (
    req.headers['x-forwarded-for']?.split(',')[0]?.trim() ||
    req.headers['x-real-ip'] ||
    '0.0.0.0'
  ).trim();

  // 1. Кэш
  if (MEM_CACHE[ip] && Date.now() - MEM_CACHE[ip].ts < 3600000) {
    return res.json({ ok:true, city:MEM_CACHE[ip].city, ip, source:'cache' });
  }

  let city = null;
  let source = 'default';

  // 2. Локальная база IP2Location
  const ipInt = ipToInt(ip);
  if (ipInt > 0) {
    city = lookupCity(ipInt);
    if (city) source = 'ip2location_local';
  }

  // 3. ip-api.com (fallback)
  if (!city) {
    try {
      const r = await fetch(`http://ip-api.com/json/${ip}?fields=city,country&lang=ru`);
      if (r.ok) {
        const d = await r.json();
        if (d.city && d.country === 'Russia') { city = d.city; source = 'ip-api'; }
      }
    } catch(_) {}
  }

  // 4. freeipapi.com (fallback)
  if (!city) {
    try {
      const r2 = await fetch(`https://freeipapi.com/api/json/${ip}`);
      if (r2.ok) {
        const d2 = await r2.json();
        if (d2.cityName && d2.countryCode === 'RU') { city = d2.cityName; source = 'freeipapi'; }
      }
    } catch(_) {}
  }

  if (!city) { city = 'Волгоград'; source = 'default'; }

  MEM_CACHE[ip] = { city, ts: Date.now() };
  res.json({ ok:true, city, ip, source, ts:Date.now() });
}
